SELECT COUNT(*) FROM postgres.comments as c, postgres.posts as p, postgres.postLinks as pl, postgres.postHistory as ph, postgres.votes as v, postgres.badges as b WHERE p.Id = c.PostId AND p.Id = pl.RelatedPostId AND p.Id = ph.PostId AND p.Id = v.PostId AND b.UserId = c.UserId AND v.CreationDate>='2010-07-19 00:00:00'::timestamp AND v.CreationDate<='2014-09-10 00:00:00'::timestamp;
